// Code generated by hand for performance.
// SPDX-License-Identifier: Apache-2.0
//
// Fused NEON activations for f32:
//   sigmoid(x) = 1 / (1 + exp(-x))
//   silu(x)    = x * sigmoid(x) = x / (1 + exp(-x))
//   tanh(x)    = (exp(2x) - 1) / (exp(2x) + 1)
//
// All evaluate exp() inline via the 7th-order Taylor polynomial after
// Cody-Waite range reduction, then combine with FMUL/FDIV. Real NEON
// per AGENTS.md §1.1.

#include "textflag.h"

#define VFADD_S4(m, n, d)  WORD $(0x4E20D400 | ((m) << 16) | ((n) << 5) | (d))
#define VFSUB_S4(m, n, d)  WORD $(0x4EA0D400 | ((m) << 16) | ((n) << 5) | (d))
#define VFMUL_S4(m, n, d)  WORD $(0x6E20DC00 | ((m) << 16) | ((n) << 5) | (d))
#define VFMLA_S4(m, n, d)  WORD $(0x4E20CC00 | ((m) << 16) | ((n) << 5) | (d))
#define VFDIV_S4(m, n, d)  WORD $(0x6E20FC00 | ((m) << 16) | ((n) << 5) | (d))
#define VFNEG_S4(n, d)     WORD $(0x6EA0F800 | ((n) << 5) | (d))
#define VFRINTN_S4(n, d)   WORD $(0x4E218800 | ((n) << 5) | (d))
#define VFCVTZS_S4(n, d)   WORD $(0x4EA1B800 | ((n) << 5) | (d))
#define VADD_S4(m, n, d)   WORD $(0x4EA08400 | ((m) << 16) | ((n) << 5) | (d))
#define VSHL_S4_BY23(n, d) WORD $(0x4F375400 | ((n) << 5) | (d))
#define VMOV_B16(src, dst) WORD $(0x4EA01C00 | ((src) << 16) | ((src) << 5) | (dst))

// Activation constants: same layout as expC but re-exported under a
// separate symbol so this file remains self-contained.
DATA  actC<>+0(SB)/4, $1.4426950408889634   // log2e
DATA  actC<>+4(SB)/4, $0.6931471805599453   // ln2
DATA  actC<>+8(SB)/4, $127.0                // bias
DATA  actC<>+12(SB)/4, $0.00019841270       // c7
DATA  actC<>+16(SB)/4, $0.0013888889        // c6
DATA  actC<>+20(SB)/4, $0.008333334         // c5
DATA  actC<>+24(SB)/4, $0.041666667         // c4
DATA  actC<>+28(SB)/4, $0.16666667          // c3
DATA  actC<>+32(SB)/4, $0.5                 // c2
DATA  actC<>+36(SB)/4, $1.0                 // c1
DATA  actC<>+40(SB)/4, $1.0                 // c0
DATA  actC<>+44(SB)/4, $2.0                 // 2.0 for tanh
GLOBL actC<>(SB), 8, $48

// EXP_BODY computes V_in.S4 → exp(V_in) in V_out.S4. Trashes V1-V5,
// V_in (so the caller saves it first if needed). Constants V16-V27
// must be pre-loaded.
#define EXP_BODY(in, out) \
    VFMUL_S4(16, in, 1)                  \
    VFRINTN_S4(1, 1)                     \
    VFMUL_S4(17, 1, 2)                   \
    VFSUB_S4(2, in, in)                  \
    VMOV_B16(19, 3)                      \
    VMOV_B16(20, 4) ; VFMLA_S4(in, 3, 4) \
    VMOV_B16(21, 3) ; VFMLA_S4(in, 4, 3) \
    VMOV_B16(22, 4) ; VFMLA_S4(in, 3, 4) \
    VMOV_B16(23, 3) ; VFMLA_S4(in, 4, 3) \
    VMOV_B16(24, 4) ; VFMLA_S4(in, 3, 4) \
    VMOV_B16(25, 3) ; VFMLA_S4(in, 4, 3) \
    VMOV_B16(26, 4) ; VFMLA_S4(in, 3, 4) \
    VFCVTZS_S4(1, 5)                     \
    VADD_S4(27, 5, 5)                    \
    VSHL_S4_BY23(5, 5)                   \
    VFMUL_S4(5, 4, out)

// LOAD_EXP_CONSTS broadcasts the 11 polynomial constants into V16-V26
// plus the int 127 broadcast into V27. Call once at function entry.
#define LOAD_EXP_CONSTS \
    MOVD $actC<>(SB), R3                              \
    FMOVS  0(R3), F16 ; VDUP V16.S[0], V16.S4         \
    FMOVS  4(R3), F17 ; VDUP V17.S[0], V17.S4         \
    FMOVS  8(R3), F18 ; VDUP V18.S[0], V18.S4         \
    FMOVS 12(R3), F19 ; VDUP V19.S[0], V19.S4         \
    FMOVS 16(R3), F20 ; VDUP V20.S[0], V20.S4         \
    FMOVS 20(R3), F21 ; VDUP V21.S[0], V21.S4         \
    FMOVS 24(R3), F22 ; VDUP V22.S[0], V22.S4         \
    FMOVS 28(R3), F23 ; VDUP V23.S[0], V23.S4         \
    FMOVS 32(R3), F24 ; VDUP V24.S[0], V24.S4         \
    FMOVS 36(R3), F25 ; VDUP V25.S[0], V25.S4         \
    FMOVS 40(R3), F26 ; VDUP V26.S[0], V26.S4         \
    VFCVTZS_S4(18, 27)

// func sigmoidFloat32NEONAsm(dst, src *float32, n int)
// sigmoid(x) = 1 / (1 + exp(-x))
TEXT ·sigmoidFloat32NEONAsm(SB), NOSPLIT, $0-24
    MOVD dst+0(FP), R0
    MOVD src+8(FP), R1
    MOVD n+16(FP), R2
    LOAD_EXP_CONSTS

sigmoid_loop4:
    CMP  $4, R2
    BLT  sigmoid_scalar_tail
    VLD1.P 16(R1), [V0.S4]
    VFNEG_S4(0, 0)                                    // V0 = -x
    EXP_BODY(0, 6)                                    // V6 = exp(-x)
    // V6 += 1
    VFADD_S4(26, 6, 6)
    // sigmoid = 1 / V6.  c0 (V26) is 1.0.
    VFDIV_S4(6, 26, 7)                                // V7 = 1 / V6
    VST1.P [V7.S4], 16(R0)
    SUB  $4, R2
    B    sigmoid_loop4

sigmoid_scalar_tail:
    CBZ  R2, sigmoid_done

sigmoid_scalar_loop:
    FMOVS (R1), F0
    VDUP V0.S[0], V0.S4
    VFNEG_S4(0, 0)
    EXP_BODY(0, 6)
    VFADD_S4(26, 6, 6)
    VFDIV_S4(6, 26, 7)
    FMOVS F7, (R0)
    ADD  $4, R1
    ADD  $4, R0
    SUB  $1, R2
    CBNZ R2, sigmoid_scalar_loop

sigmoid_done:
    RET

// func siluFloat32NEONAsm(dst, src *float32, n int)
// silu(x) = x / (1 + exp(-x))
TEXT ·siluFloat32NEONAsm(SB), NOSPLIT, $0-24
    MOVD dst+0(FP), R0
    MOVD src+8(FP), R1
    MOVD n+16(FP), R2
    LOAD_EXP_CONSTS

silu_loop4:
    CMP  $4, R2
    BLT  silu_scalar_tail
    VLD1.P 16(R1), [V0.S4]
    // Keep x in V8 since EXP_BODY clobbers V0.
    VMOV_B16(0, 8)
    VFNEG_S4(0, 0)
    EXP_BODY(0, 6)
    VFADD_S4(26, 6, 6)
    VFDIV_S4(6, 8, 7)                                 // V7 = x / (1 + exp(-x))
    VST1.P [V7.S4], 16(R0)
    SUB  $4, R2
    B    silu_loop4

silu_scalar_tail:
    CBZ  R2, silu_done

silu_scalar_loop:
    FMOVS (R1), F0
    VDUP V0.S[0], V0.S4
    VMOV_B16(0, 8)
    VFNEG_S4(0, 0)
    EXP_BODY(0, 6)
    VFADD_S4(26, 6, 6)
    VFDIV_S4(6, 8, 7)
    FMOVS F7, (R0)
    ADD  $4, R1
    ADD  $4, R0
    SUB  $1, R2
    CBNZ R2, silu_scalar_loop

silu_done:
    RET

// func tanhFloat32NEONAsm(dst, src *float32, n int)
// tanh(x) = (e^{2x} - 1) / (e^{2x} + 1)
TEXT ·tanhFloat32NEONAsm(SB), NOSPLIT, $0-24
    MOVD dst+0(FP), R0
    MOVD src+8(FP), R1
    MOVD n+16(FP), R2
    LOAD_EXP_CONSTS
    // V28 = 2.0 broadcast for the 2x scaling.
    FMOVS 44(R3), F28 ; VDUP V28.S[0], V28.S4

tanh_loop4:
    CMP  $4, R2
    BLT  tanh_scalar_tail
    VLD1.P 16(R1), [V0.S4]
    VFMUL_S4(28, 0, 0)                                // V0 = 2x
    EXP_BODY(0, 6)                                    // V6 = e^{2x}
    // numerator = V6 - 1
    // denominator = V6 + 1
    VFSUB_S4(26, 6, 8)                                // V8 = V6 - 1 (need -1; V26=1, but FSUB Vd = Vm - Vn? Check)
    // VFSUB_S4(m, n, d): Vd = Vn - Vm. So d = n - m. With m=26 (c=1), n=6: V8 = V6 - 1 ✓
    VFADD_S4(26, 6, 9)                                // V9 = V6 + 1
    VFDIV_S4(9, 8, 7)                                 // V7 = V8 / V9
    VST1.P [V7.S4], 16(R0)
    SUB  $4, R2
    B    tanh_loop4

tanh_scalar_tail:
    CBZ  R2, tanh_done

tanh_scalar_loop:
    FMOVS (R1), F0
    VDUP V0.S[0], V0.S4
    VFMUL_S4(28, 0, 0)
    EXP_BODY(0, 6)
    VFSUB_S4(26, 6, 8)
    VFADD_S4(26, 6, 9)
    VFDIV_S4(9, 8, 7)
    FMOVS F7, (R0)
    ADD  $4, R1
    ADD  $4, R0
    SUB  $1, R2
    CBNZ R2, tanh_scalar_loop

tanh_done:
    RET
